#include <stdio.h>

int main()
{
	int m,n,t,u,maxi,i;
	scanf("%d %d",&m,&n);
	maxi=m;
	if (n>maxi){
		maxi=n;
	}
	t=6-maxi+1;
	u=6;
	for (i=6;i>1;i--){
		if (t%i==0 && u%i==0){
			printf("%d/%d",t/i,u/i);
			return 0;
		}
	}

	printf("%d/%d",t,u);



	return 0;
}

